1→use rustc_ast::{self as ast, attr};
     2→use rustc_expand::base::{ExtCtxt, ResolverExpand};
     3→use rustc_expand::expand::ExpansionConfig;
     4→use rustc_feature::Features;
     5→use rustc_session::Session;
     6→use rustc_span::edition::Edition::*;
